def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    def prime_factors_sum(num):
        total = 0
        for p in range(2, int(num//2) + 1):
            if num % p == 0 and is_prime(p):
                total += p ** 1.1
        return total
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = 500 if item > cap else -500
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            wave_sum = 0
            for freq in range(1, 12):
                wave_sum += np.sin(freq * cap * 0.23 + ratio * freq**2) / freq
            score += wave_sum * 25
            prime_sum = prime_factors_sum(cap)
            score += prime_sum * 2.3
            if cap % 7 == 0:
                score *= 1.15
            for i in range(1, int(min(cap, 20))):
                if i % 2 == 0 and cap % i == 0:
                    score += (i**0.5) * np.log1p(i) * 1.7
        elif 0.1 <= ratio < 0.3:
            base_score = np.tanh((0.3 - ratio) * 12) * 20
            exp_decay = np.exp(-cap * 0.05)
            score += base_score * exp_decay
            for d in range(2, 15):
                if cap % d == 0:
                    score += np.cos(d * ratio * np.pi) * d * 0.8
            if is_prime(int(cap)):
                score += 18
            mod_sum = 0
            for m in range(5, 12):
                mod_sum += ((cap % m) / (m + 1)) * (ratio * m)**1.3
            score += mod_sum * 0.9
        elif 0.3 <= ratio < 0.6:
            sine_component = 0
            for s in range(3,10):
                sine_component += np.sin(s * ratio * np.pi) * (s**0.6)
            score += sine_component * 7
            for p in range(2, int(min(15, cap))):
                if cap % p == 0 and p % 5 == 3:
                    score += np.sqrt(p) * 3.3
            factorial_mod = 0
            for fact_term in range(1,5):
                fact = 1
                for f in range(1, fact_term*2 + 1):
                    fact *= f
                factorial_mod += (ratio**fact_term) / fact
            score += factorial_mod * -12
            if int(cap) % 9 == 0:
                score *= 0.85
        elif 0.6 <= ratio < 1.0:
            logistic_part = 40 / (1 + np.exp(-30 * (ratio - 0.75)))
            sine_modulator = np.sin(cap * ratio * 0.5) * 15
            score += logistic_part + sine_modulator
            prime_adjust = 0
            for h in range(2, 20):
                if is_prime(h) and h % 4 == 3:
                    prime_adjust += h * 1.25
            score += prime_adjust
            if ratio > 0.85:
                score += (1 - ratio) * 45
            if cap % 8 == 0:
                score *= 1.12
            for div_check in range(3,10):
                if cap % div_check == 0:
                    score += np.log1p(div_check) * 2
        elif 1.0 <= ratio < 2.0:
            penalty = 0
            step = max(1, int(cap//6))
            for i in range(1, step + 2):
                if cap % i == 0:
                    penalty += (i ** 2.1) * 0.6
            fractional_part = ratio - int(ratio)
            for j in range(1, 12):
                mod_val = (fractional_part * j * 1000) % 7
                penalty += (mod_val / 7) * 8
            score += penalty / (step + 3)
            score += (ratio - 1) * (-75)
            if int(cap) % 17 == 0:
                score *= 0.92
            if int(cap) % 19 == 0:
                score += 27
        elif 2.0 <= ratio < 3.5:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    parity = k % 2
                    if parity == 1:
                        complex_sum += np.sqrt(k * ratio) * 3
                    else:
                        complex_sum += np.log1p(k * ratio) * 2.5
            fract_part = ratio - int(ratio)
            for m in range(1,15):
                complex_sum += np.sin(fract_part * m * np.pi * 1.5) * 3
            score += complex_sum
            score += (ratio - 2) * 90
            if ratio > 2.7:
                for n in range(1, int(cap // 4) + 1):
                    if n % 5 == 0:
                        score += np.cos(n * ratio) * 5
        else:
            huge_sum = 0
            for p1 in range(1, int(min(25, cap))):
                if cap % p1 == 0:
                    val = np.sqrt(p1 * ratio) * 2.5 if p1 % 3 else np.log1p(p1 * ratio) * 3.5
                    huge_sum += val * ((-1)**p1)
            fract_part2 = ratio - int(ratio)
            for q in range(1,25):
                huge_sum += np.cos(fract_part2 * q * np.pi / 2) * 4
            score += huge_sum
            score += (ratio - 3.5) * 110
            if ratio > 5:
                for r in range(1, int(cap // 2) + 1):
                    if r % 11 == 0:
                        score += np.sin(r * ratio) * 7
        if int(cap) % 3 == 0 and ratio < 1.6:
            score *= 1.13
        if int(cap) % 6 == 0 and ratio > 0.4:
            score *= 0.68
        if ratio > 4 and int(cap) % 15 == 0:
            score += 33
        if int(cap) % 20 == 0:
            score *= 0.79
        if np.isclose(ratio, 1.0, atol=0.02):
            score += 25
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 350)
    return priorities
